  icon: Icon,
  kicker,
  title,
  as: Tag = "h2",
  preset = "section",
  titleClassName,
  kickerRowClassName,
  iconClassName,
  className,
}: SiteSectionHeadingProps) {
  const titleCls = titleClassName ?? TITLE_PRESETS[preset];

   const kickerBlock =
