import { SectionHeading } from "@/components/SectionHeading";
import { loadPlanningData } from "@/lib/planning-data";
import { PlanningTabbedContent } from "./PlanningTabbedContent";

export const dynamic = "force-dynamic";
export const runtime = "nodejs";

export const metadata = {
  title: "Planning — GAD Planning",
  description:
    "Tasks, decisions, roadmap, requirements, notes, and system telemetry for the active planning root.",
};

interface PlanningPageProps {
  searchParams: Promise<{ project?: string; tab?: string; sub?: string }>;
}

export default async function PlanningPage({
  searchParams,
}: PlanningPageProps) {
  const params = await searchParams;
  const projectId = params.project || "get-anything-done";
  const data = loadPlanningData(projectId);

  if (!data) {
    return (
      <div className="mx-auto w-full max-w-6xl px-6 py-12">
        <SectionHeading
          kicker="Planning"
          title="Planning root not found"
          description={
            <>
              Could not resolve <code className="font-mono">{projectId}</code>{" "}
              against the monorepo. Phase 59 wires only the GAD repo by default;
              multi-project scoping lands in task 59-04.
            </>
          }
        />
      </div>
    );
  }

  return (
    <div className="mx-auto w-full max-w-6xl px-6 py-10">
      <SectionHeading
        kicker="Planning"
        title={`Planning — ${data.projectId}`}
        description={
          <>
            Ported from landing <code className="font-mono">/planning</code>{" "}
            (task 59-03). Data read live from{" "}
            <code className="font-mono">.planning/*.xml</code>.
          </>
        }
      />
      <PlanningTabbedContent data={data} />
    </div>
  );
}

