"use client";

import { useMemo, useState } from "react";
import type { PlanningDecision } from "@/lib/planning-data";

interface DecisionsTabProps {
  decisions: PlanningDecision[];
}

const DEFAULT_VISIBLE = 30;

export function DecisionsTab({ decisions }: DecisionsTabProps) {
  const [query, setQuery] = useState("");
  const [expanded, setExpanded] = useState(false);

  const ordered = useMemo(() => [...decisions].reverse(), [decisions]);

  const filtered = useMemo(() => {
    if (!query.trim()) return ordered;
    const q = query.trim().toLowerCase();
    return ordered.filter((d) =>
      `${d.id} ${d.title} ${d.summary}`.toLowerCase().includes(q),
    );
  }, [ordered, query]);

  const visible = expanded ? filtered : filtered.slice(0, DEFAULT_VISIBLE);
  const hasMore = filtered.length > DEFAULT_VISIBLE;

  if (decisions.length === 0) {
    return (
      <div className="rounded-md border border-border/60 bg-muted/20 px-4 py-3 text-xs text-muted-foreground">
        No decisions recorded.
      </div>
    );
  }

  return (
    <div data-cid="planning-decisions-tab">
      <div className="mb-4 flex flex-wrap items-center gap-3 text-sm text-muted-foreground">
        <span>
          <strong className="text-foreground">{decisions.length}</strong> decisions
        </span>
        <input
          type="search"
          placeholder="Filter…"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          className="ml-auto rounded border border-border bg-card px-2 py-1 text-xs text-foreground placeholder:text-muted-foreground focus:border-accent focus:outline-none"
        />
      </div>
      <div className="space-y-2">
        {visible.map((d) => (
          <div
            key={d.id}
            className="flex items-start gap-3 rounded-lg border border-border/50 bg-card/30 p-3"
          >
            <code className="shrink-0 rounded-md bg-background/60 px-2 py-1 font-mono text-[10px] text-accent">
              {d.id}
            </code>
            <div className="min-w-0 flex-1">
              <p className="text-xs font-medium text-foreground">{d.title}</p>
              {d.summary && (
                <p className="mt-1 text-[11px] leading-5 text-muted-foreground line-clamp-3">
                  {d.summary}
                </p>
              )}
            </div>
          </div>
        ))}
      </div>
      {hasMore && (
        <button
          type="button"
          onClick={() => setExpanded((v) => !v)}
          className="mt-3 text-xs font-medium text-accent hover:underline"
        >
          {expanded
            ? `Show latest ${DEFAULT_VISIBLE} only`
            : `Show all ${filtered.length} decisions`}
        </button>
      )}
    </div>
  );
}

