"use client";

import { useMemo } from "react";
import type { PlanningRequirement } from "@/lib/planning-data";

interface RequirementsTabProps {
  requirements: PlanningRequirement[];
}

export function RequirementsTab({ requirements }: RequirementsTabProps) {
  const grouped = useMemo(() => {
    const map = new Map<string, PlanningRequirement[]>();
    for (const req of requirements) {
      const key = req.kind || "uncategorized";
      const list = map.get(key);
      if (list) list.push(req);
      else map.set(key, [req]);
    }
    return [...map.entries()];
  }, [requirements]);

  if (requirements.length === 0) {
    return (
      <div
        data-cid="planning-requirements-tab"
        className="rounded-md border border-dashed border-border/50 bg-muted/10 px-4 py-6 text-center text-xs text-muted-foreground"
      >
        No requirements found.
      </div>
    );
  }

  return (
    <div data-cid="planning-requirements-tab" className="space-y-4">
      <div className="text-sm text-muted-foreground">
        <strong className="text-foreground">{requirements.length}</strong>{" "}
        requirement {requirements.length === 1 ? "entry" : "entries"} across{" "}
        <strong className="text-foreground">{grouped.length}</strong>{" "}
        {grouped.length === 1 ? "category" : "categories"}
      </div>

      {grouped.map(([kind, items]) => (
        <div
          key={kind}
          className="rounded-xl border border-border/60 bg-card/40 p-5"
        >
          <div className="mb-3 flex items-center gap-3">
            <span className="rounded-full border border-accent/40 bg-accent/10 px-2 py-0.5 text-[10px] font-semibold uppercase tracking-wider text-accent">
              {kind.replace(/[-_]/g, " ")}
            </span>
            <span className="text-xs text-muted-foreground">
              {items.length} {items.length === 1 ? "doc" : "docs"}
            </span>
          </div>
          <div className="space-y-3">
            {items.map((req, i) => (
              <div key={`${kind}-${i}`} className="space-y-1">
                {req.docPath && (
                  <p className="font-mono text-[11px] text-accent/80">
                    {req.docPath}
                  </p>
                )}
                {req.description && (
                  <p className="whitespace-pre-line text-xs leading-5 text-foreground/90">
                    {req.description}
                  </p>
                )}
              </div>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
}

