"use client";

import type { PlanningState } from "@/lib/planning-data";

interface SystemTabProps {
  projectId: string;
  state: PlanningState | null;
}

function StatCard({
  label,
  value,
  sub,
}: {
  label: string;
  value: string | number;
  sub?: string;
}) {
  return (
    <div className="rounded-md border border-border/60 bg-card/40 px-4 py-3">
      <p className="text-[10px] font-semibold uppercase tracking-wider text-muted-foreground">
        {label}
      </p>
      <p className="mt-1 text-xl font-semibold tabular-nums text-foreground">
        {value}
      </p>
      {sub ? (
        <p className="mt-0.5 text-[10px] text-muted-foreground">{sub}</p>
      ) : null}
    </div>
  );
}

export function SystemTab({ projectId, state }: SystemTabProps) {
  return (
    <div data-cid="planning-system-tab" className="space-y-4">
      <div className="grid gap-3 md:grid-cols-3">
        <StatCard label="Project" value={projectId} />
        <StatCard
          label="Current phase"
          value={state?.currentPhase ?? "—"}
          sub={state?.milestone ? `milestone ${state.milestone}` : undefined}
        />
        <StatCard
          label="Open tasks"
          value={state?.openTasks ?? 0}
        />
        <StatCard
          label="Phases complete"
          value={`${state?.phasesComplete ?? 0}${
            state?.phasesTotal != null ? ` / ${state.phasesTotal}` : ""
          }`}
        />
        <StatCard label="Status" value={state?.status ?? "—"} />
        <StatCard
          label="Last activity"
          value={
            state?.lastActivity
              ? new Date(state.lastActivity).toLocaleDateString()
              : "—"
          }
        />
      </div>

      {state?.nextAction ? (
        <div className="rounded-md border border-accent/40 bg-accent/10 p-4">
          <p className="text-[10px] font-semibold uppercase tracking-wider text-accent">
            Next action
          </p>
          <p className="mt-1 text-sm text-foreground whitespace-pre-line">
            {state.nextAction}
          </p>
        </div>
      ) : null}

      <div className="rounded-md border border-border/60 bg-muted/10 p-4">
        <p className="text-[10px] font-semibold uppercase tracking-wider text-muted-foreground">
          Runtime telemetry
        </p>
        <p className="mt-2 text-xs text-muted-foreground">
          Per-task framework overhead, token totals, and live activity feed
          land alongside the /my-projects dashboard in task 59-04. Phase 59
          ships the planning doc surfaces; system telemetry stays behind the
          existing landing <code className="font-mono">/api/dev/evals/projects/[id]/system</code>{" "}
          endpoint until the planning-app adapter is wired.
        </p>
      </div>
    </div>
  );
}

