/**
 * SubagentRunHistory — empty-state today (task 59-04).
 *
 * When phase 59-07 starts writing `.planning/subagent-runs/<projectid>/*.json`
 * records, this component already reads from them; phase 59-09 will flesh out
 * the full timeline row rendering (tip links, report body drawer, etc.).
 *
 * R6 mitigation: `loadSubagentRunHistory` in projects-data skips unparseable
 * files so a partial write never crashes the drawer.
 */
export function SubagentRunHistory({
  projectId,
  runs,
  dirExists,
  dir,
}: {
  projectId: string;
  runs: SubagentRunRecord[];
  dirExists: boolean;
  dir: string;
}) {
  if (runs.length === 0) {
    return (
      <div
        data-cid={`subagent-runs-empty-${projectId}`}
        className="rounded-md border border-dashed border-border/60 bg-muted/10 px-4 py-6 text-center"
      >
        <p className="text-xs text-muted-foreground">
          No subagent runs recorded yet.
        </p>
        <p className="mt-1 text-[11px] text-muted-foreground/80">
          {dirExists ? (
            <>
              Watching{" "}
              <code className="font-mono">
                .planning/subagent-runs/{projectId}/
              </code>
              . Phase 59-07 wires the daily dispatch; 59-09 fleshes out this
              timeline.
            </>
          ) : (
            <>
              Will populate from{" "}
              <code className="font-mono">
                .planning/subagent-runs/{projectId}/*.json
              </code>{" "}
              once phase 59-07 dispatches a run.
            </>
          )}
        </p>
      </div>
    );
  }

  return (
    <ul
      data-cid={`subagent-runs-list-${projectId}`}
      className="space-y-1.5"
      data-runs-dir={dir}
    >
      {runs.map((r) => (
        <li
          key={r.runId}
          className="flex items-start gap-3 rounded-md border border-border/50 bg-card/30 p-2 text-[11px]"
        >
          <code className="shrink-0 font-mono text-muted-foreground">
            {r.startedAt?.slice(0, 10) ?? "—"}
          </code>
          <code className="shrink-0 font-mono text-muted-foreground">
            {r.taskId}
          </code>
          <span className="min-w-0 flex-1 truncate text-foreground">
            {r.oneLineOutcome ?? "(no outcome recorded)"}
          </span>
          <span className="shrink-0 rounded-full border border-border/60 px-2 py-0.5 text-[9px] uppercase tracking-wider text-muted-foreground">
            {r.status}
          </span>
        </li>
      ))}
    </ul>
  );
}

