import { SectionHeading } from "@/components/SectionHeading";
import { loadAllProjects, loadProjectDetail } from "@/lib/projects-data";
import { ProjectCard } from "./ProjectCard";
import { ProjectDrawer } from "./ProjectDrawer";

export const dynamic = "force-dynamic";
export const runtime = "nodejs";

export const metadata = {
  title: "My Projects — GAD Planning",
};

interface MyProjectsPageProps {
  searchParams: Promise<{ projectid?: string }>;
}

export default async function MyProjectsPage({
  searchParams,
}: MyProjectsPageProps) {
  const params = await searchParams;
  const activeProjectId = params.projectid?.trim() || null;

  const { cards, repoRoot } = loadAllProjects();
  const detail = activeProjectId ? loadProjectDetail(activeProjectId) : null;

  return (
    <div className="mx-auto w-full max-w-6xl px-6 py-10">
      <SectionHeading
        kicker="Dashboard"
        title="My Projects"
        description={
          <>
            {cards.length} project{cards.length === 1 ? "" : "s"} registered in{" "}
            <code className="font-mono">gad-config.toml</code>
            {" "}at{" "}
            <code className="font-mono">{repoRoot}</code>. Phase, next-action,
            open tasks, decisions, subagent runs, BYOK status live here. Click
            a card to open its drawer; use{" "}
            <code className="font-mono">view planning →</code> to jump into the
            full XML surface.
          </>
        }
      />

      {activeProjectId && !detail ? (
        <div
          data-cid="my-projects-drawer-missing"
          className="mb-6 rounded-md border border-rose-500/40 bg-rose-500/10 px-4 py-3 text-xs text-rose-300/90"
        >
          Project <code className="font-mono">{activeProjectId}</code> is not
          registered in gad-config.toml or its .planning/ dir is missing.
        </div>
      ) : null}

      {detail ? <ProjectDrawer detail={detail} /> : null}

      {cards.length === 0 ? (
        <div
          data-cid="my-projects-empty"
          className="rounded-md border border-dashed border-border/60 bg-muted/10 px-4 py-6 text-center text-xs text-muted-foreground"
        >
          No <code className="font-mono">[[planning.roots]]</code> entries
          found in gad-config.toml. Run{" "}
          <code className="font-mono">gad workspace add &lt;path&gt;</code> to
          register one.
        </div>
      ) : (
        <div
          data-cid="my-projects-grid"
          className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3"
        >
          {cards.map((card) => (
            <ProjectCard
              key={card.id}
              card={card}
              active={card.id === activeProjectId}
            />
          ))}
        </div>
      )}
    </div>
  );
}

