 */
export function resolveProjectBaseDir(projectId: string): string | null {
  const repoRoot = findRepoRoot();
  if (!repoRoot) return null;

  const candidates: Record<string, string[]> = {
    "get-anything-done": [path.join(repoRoot, "vendor", "get-anything-done")],
  };

  // Also attempt `projects/<id>` for any project registered via workspace
  // convention (llm-from-scratch etc).
