/**
 * Map project-id to its filesystem root within the monorepo.
 *
 * Original 59-03 scope: only "get-anything-done" (+ `projects/<id>` guess).
 * 59-04 extends this with a `gad-config.toml` lookup so every registered
 * planning root resolves — the /my-projects drawer's "view planning" links
 * route to `/planning?projectid=<id>` for arbitrary projects.
 */
export function resolveProjectBaseDir(projectId: string): string | null {
  const repoRoot = findRepoRoot();
  if (!repoRoot) return null;

  // Hardcoded fast path (preserves 59-03 behavior when toml is absent).
  const candidates: string[] = [];
  if (projectId === "get-anything-done") {
    candidates.push(path.join(repoRoot, "vendor", "get-anything-done"));
  }
  candidates.push(path.join(repoRoot, "projects", projectId));

  for (const dir of candidates) {
    if (fs.existsSync(path.join(dir, ".planning"))) return dir;
  }

  // Fallback: consult gad-config.toml [[planning.roots]] for any registered
  // project root. Added in 59-04. Minimal inline parse — same approach as
  // projects-data.ts (regex key-extract; no TOML dep).
  const tomlPath = path.join(repoRoot, "gad-config.toml");
  if (!fs.existsSync(tomlPath)) return null;
  try {
    const text = fs.readFileSync(tomlPath, "utf8");
    const re = /\[\[planning\.roots\]\]([\s\S]*?)(?=\n\[|$)/g;
    let m: RegExpExecArray | null;
    while ((m = re.exec(text)) !== null) {
      const body = m[1];
      const idMatch = body.match(/^\s*id\s*=\s*"([^"]+)"/m);
      const pathMatch = body.match(/^\s*path\s*=\s*"([^"]+)"/m);
      if (!idMatch || !pathMatch) continue;
      if (idMatch[1] !== projectId) continue;
      const rel = pathMatch[1].replace(/\\\\/g, "\\").replace(/\\/g, "/");
      const abs =
        path.isAbsolute(rel) || rel === "."
          ? path.resolve(repoRoot, rel)
          : path.join(repoRoot, rel);
      if (fs.existsSync(path.join(abs, ".planning"))) return abs;
      return null;
    }
  } catch {
    // ignore — degrade to null
  }
  return null;
}

