function addPhaseToRegistryXml(xml, phaseId, opts = {}) {
  const normalized = validatePhaseId(phaseId);
  const phaseOpenRe = new RegExp(`<phase\\s+id="${escapeRegex(normalized)}"\\b`);
  if (phaseOpenRe.test(xml)) {
