        filePath: '/fake/TASK-REGISTRY.xml',
        def: { id: '01-01', phase: '01', goal: 'dup' },
        fsImpl: fake,
      }),
      (e) => e instanceof TaskWriterError && e.code === 'TASK_ID_EXISTS',
    );
    assert.strictEqual(fake.store['/fake/TASK-REGISTRY.xml'], BASE_XML);
  });

