cd /c/Users/benja/Documents/custom_portfolio/vendor/get-anything-done

# Use awk to process files
get_lane() {
  case "$1" in
    build-and-release-locally|portfolio-sync|gad-evolution-images) echo "prod" ;;
    create-skill|create-proto-skill|merge-skill|find-skills|eval-skill-install|gad-skill-creator|gad-proto-skill-battery|gad-evolution-evolve|gad-evolution-validator|gad-discovery-test|gad-snapshot-optimize|framework-upgrade|gad-update|gad-reapply-patches|gad-cross-config-domain-change|objective-eval-design|self-eval|trace-analysis|gad-eval-bootstrap|gad-eval-suite) echo "meta" ;;
    gad-debug|gad-forensics|gad-reverse-engineer|gad-auto-conventions) echo "[dev, meta]" ;;
    gad-verify-work|gad-validate-phase) echo "[dev, prod]" ;;
    *) echo "dev" ;;
  esac
}

processed=0
for skill_dir in skills/*/; do
  skill_name=$(basename "$skill_dir")
  skill_md="$skill_dir/SKILL.md"

  [ "$skill_name" = "gad-add-backlog" ] && continue  # Already done
  [ ! -f "$skill_md" ] && continue

  # Skip if already has lane
  if grep -q "^lane:" "$skill_md" 2>/dev/null; then
    continue
  fi

  # Skip if no frontmatter
  if ! head -1 "$skill_md" | grep -q "^---"; then
    continue
  fi

  lane=$(get_lane "$skill_name")

  # Use awk to insert lane after description
  awk -v lane="$lane" '
    BEGIN { in_fm = 0; found_desc = 0; added_lane = 0 }
    NR == 1 { if ($0 ~ /^---/) in_fm = 1 }
    in_fm && /^---/ && NR > 1 { in_fm = 0; if (!added_lane) print "lane: " lane }
    in_fm && /^description:/ { found_desc = 1; print; getline; if (!($0 ~ /^\s*$/)) { print "lane: " lane; added_lane = 1 } print; next }
    { print }
  ' "$skill_md" > "$skill_md.tmp" && mv "$skill_md.tmp" "$skill_md"

  ((processed++))
  [ $((processed % 10)) -eq 0 ] && echo "Processed: $processed skills..."
done

echo "Done processing skills"

cd /c/Users/benja/Documents/custom_portfolio/vendor/get-anything-done

# Get lane for each skill
get_lane() {
  case "$1" in
    build-and-release-locally|portfolio-sync|gad-evolution-images) echo "prod" ;;
    create-skill|create-proto-skill|merge-skill|find-skills|eval-skill-install|gad-skill-creator|gad-proto-skill-battery|gad-evolution-evolve|gad-evolution-validator|gad-discovery-test|gad-snapshot-optimize|framework-upgrade|gad-update|gad-reapply-patches|gad-cross-config-domain-change|objective-eval-design|self-eval|trace-analysis|gad-eval-bootstrap|gad-eval-suite) echo "meta" ;;
    gad-debug|gad-forensics|gad-reverse-engineer|gad-auto-conventions) echo "[dev, meta]" ;;
    gad-verify-work|gad-validate-phase) echo "[dev, prod]" ;;
    *) echo "dev" ;;
  esac
}

# Fix skills with >- description
for skill_dir in skills/*/; do
  skill_name=$(basename "$skill_dir")
  skill_md="$skill_dir/SKILL.md"
  [ ! -f "$skill_md" ] && continue

  if head -10 "$skill_md" | grep -A1 "description: >-" | grep -q "^lane:"; then
    lane=$(get_lane "$skill_name")

    # Read entire file
    content=$(cat "$skill_md")

    # Remove the incorrectly placed lane (it should be right after description: >-)
    content=$(echo "$content" | sed '/^description: >-$/,/^[a-z]/{ /^lane:/d; }')

    # Now find the line after "description: >-" block ends and insert lane there
    # The block ends when we hit a line that doesn't start with whitespace and isn't empty
    awk -v lane="$lane" '
      BEGIN { found_desc = 0; in_desc = 0 }
      /^description: >-/ { found_desc = 1; in_desc = 1; print; next }
      in_desc && /^[a-z]/ { print "lane: " lane; in_desc = 0; print; next }
      { print }
    ' <<< "$content" > "$skill_md.tmp" && mv "$skill_md.tmp" "$skill_md"

    echo "Fixed: $skill_name"
  fi
done

node -e "
const fs = require('fs');
const files = [
  'skills/create-proto-skill/SKILL.md',
  'skills/create-skill/SKILL.md',
  'skills/eval-skill-install/SKILL.md',
  'skills/find-skills/SKILL.md',
  'skills/merge-skill/SKILL.md',
  'skills/objective-eval-design/SKILL.md',
];
for (const f of files) {
  const raw = fs.readFileSync(f, 'utf8');
  // Find end of top frontmatter block (second --- line)
  const lines = raw.split(/\r?\n/);
  if (lines[0] !== '---') { console.log('skip no-frontmatter: ' + f); continue; }
  let endIdx = -1;
  for (let i = 1; i < lines.length; i++) {
    if (lines[i] === '---') { endIdx = i; break; }
  }
  if (endIdx === -1) { console.log('skip no-end: ' + f); continue; }
  // Keep lines 0..endIdx as-is; strip any subsequent 'lane: ' lines from body
  const head = lines.slice(0, endIdx + 1);
  const tail = lines.slice(endIdx + 1).filter(l => !/^lane:\s/.test(l));
  const out = [...head, ...tail].join('\n');
  fs.writeFileSync(f, out);
  console.log('cleaned: ' + f);
}
" 2>&1
